mapper.insert:
INSERT /* CmnMdlAmtMgmtMapper.insertMnfctAmt */
	INTO CMN_MNFCT_AMT 
	(
	  RPRS_PRDT_ID
	, OLD_YN
	, MNFCT_ID
	, UNIT_PRIC_EXPR_DTTM
	, UNIT_PRIC_APPL_DTTM
	, IN_UNIT_PRIC
	, REMRK
	, REG_ID
	, REG_DTTM
	, RVISN_ID
	, RVISN_DTTM
	)
VALUES 
	(
	  #{rprsPrdtId}
	, #{oldYn}
	, #{mnfctId}
	, #{unitPricExprDttm}||'235959'
	, TO_CHAR(TO_DATE(#{unitPricApplDttm, jdbcType=VARCHAR}, 'YYYYMMDDHH24MISS'), 'YYYYMMDDHH24MISS')
	, #{inUnitPric}
	, #{remrk}
	, #{regId}
	, SYSDATE
	, #{rvisnId}
	, SYSDATE
	)

INSERT /* CmnMdlAmtMgmtMapper.insertHndstAmt */
	INTO CMN_HNDST_AMT 
	(
	  RPRS_PRDT_ID			/* 대표제품ID */
	, OLD_YN				/* 중고여부 */
	, UNIT_PRIC_EXPR_DTTM	/* 단가만료일시 */
	, UNIT_PRIC_APPL_DTTM	/* 단가적용일시 */
	, OUT_UNIT_PRIC			/* 출고단가 */
	, MNFCT_GRANT			/* 제조사장려금 */
	, REMRK					/* 비고 */
	, REG_ID				/* 등록자ID */
	, REG_DTTM				/* 등록일시 */
	, RVISN_ID				/* 수정자ID */
	, RVISN_DTTM			/* 수정일시 */
	)
VALUES 
	(
	  #{rprsPrdtId}
	, #{oldYn}
	, #{unitPricExprDttm}||'235959'
	, TO_CHAR(TO_DATE(#{unitPricApplDttm, jdbcType=VARCHAR},'YYYYMMDDHH24MISS'), 'YYYYMMDDHH24MISS')
	, #{outUnitPric}
	, #{mnfctGrant}
	, #{remrk}
	, #{regId}
	, SYSDATE
	, #{rvisnId}
	, SYSDATE
	)
